#include<bits/stdc++.h>
using namespace std;
int main()
{
	int n,m;
	cin>>n>>m;
	int t=m;
	n/=10000;
	m/=10000;

	int cnt=0;
	for(int i=n;i<=m;i++){
		int a=i/1000%10;
		int b=i/100%10;
		int c=i/10%10;
		int d=i/1%10;
		int x=i*10000+d*1000+c*100+b*10+a;
		if(x>t)break; 
		int ri=b*10+a,yue=d*10+c;
		if(yue==2){
			if(i%100!=0&&i%4==0||i%400==0){
//				cout<<i<<" "<<yue<<" "<<ri<<" "<<(ri<=29&&ri>=0)<<endl;
				cnt+=(ri<=29&&ri>=0);
			}
			else{
//				cout<<i<<" "<<yue<<" "<<ri<<" "<<(ri<=28&&ri>=0)<<endl;
				cnt+=(ri<=28&&ri>=0);
			} 
		}else if(yue!=0&&yue<=12){
			if(yue==1||yue==3||yue==5||yue==7||yue==8||yue==10||yue==12){
//				cout<<i<<" "<<yue<<" "<<ri<<" "<<(ri<=31&&ri>=0)<<endl;
				cnt+=(ri<=31&&ri>=0);
			}
			else {
//				cout<<i<<" "<<yue<<" "<<ri<<" "<<(ri<=29&&ri>=0)<<endl;
				cnt+=(ri<=30&&ri>=0);
			}
		}
	}
	cout<<cnt<<endl;
}
